 78→async function convertColumnToBigintIfNeeded(
 79→	trx: Knex.Transaction,
 80→	tableName: string,
 81→	columnName: string,
 82→): Promise<void> {
 83→	const columnType = await trx.raw(
 84→		`
 85→		SELECT DATA_TYPE 
 86→		FROM information_schema.COLUMNS 
 87→		WHERE TABLE_SCHEMA = DATABASE() 
 88→			AND TABLE_NAME = ? 
 89→			AND COLUMN_NAME = ?
 90→	`,
 91→		[tableName, columnName],
 92→	);
 93→
 94→	if (columnType[0][0]?.DATA_TYPE === 'varchar') {
 95→		logger.log(`Converting ${tableName}.${columnName} from varchar to bigint`);
 96→		await trx.raw(`ALTER TABLE ${tableName} MODIFY COLUMN ${columnName} BIGINT NOT NULL`);
 97→	}
 98→}
