100→async function foreignKeyExists(
101→	trx: Knex.Transaction,
102→	tableName: string,
103→	constraintName: string,
104→): Promise<boolean> {
105→	const result = await trx.raw(
106→		`
107→		SELECT COUNT(*) as count
108→		FROM information_schema.TABLE_CONSTRAINTS
109→		WHERE CONSTRAINT_SCHEMA = DATABASE()
110→			AND TABLE_NAME = ?
111→			AND CONSTRAINT_NAME = ?
112→			AND CONSTRAINT_TYPE = 'FOREIGN KEY'
113→	`,
114→		[tableName, constraintName],
115→	);
116→
117→	return result[0][0].count > 0;
118→}
